interface.definition:
a!localVariables(
  local!notificationsPagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(
    startIndex: 1,
    batchSize: 3,
    sort: #"SYSTEM_SYSRULES_sortInfo"(
      field: #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/53b2c144-14a6-4aba-8c99-9959510e556b",
      ascending: false
    )
  ),
  local!notifications: a!refreshVariable(
    value: #"SYSTEM_SYSRULES_queryRecordType_v2"(
      recordType: #"urn:appian:record-type:v1:71bbaaf2-f886-43c9-8a84-0b885e738000",
      filters: {
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/4109597e-a1f6-4bdf-9e91-e7733b4f9c95/1ae3465f-b22e-4ab3-8656-a047e5f9c3e7",
          operator: "=",
          value: user(loggedInUser(), "username")
        ),
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/53b2c144-14a6-4aba-8c99-9959510e556b",
          operator: "<=",
          value: a!addDateTime(startDateTime: now(), days: #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1654086")
        ),
        #"SYSTEM_SYSRULES_queryFilter"(
          field: #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/cfe37f55-bc30-4340-b2a5-3cb36ff4e06b",
          operator: "=",
          value: true
        )
      },
      pagingInfo: local!notificationsPagingInfo,
      fetchTotalCount: true
    ),
    refreshInterval: 1,
    refreshAlways: true
  ),

  #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418867"(
    contents: #"SYSTEM_SYSRULES_sectionLayout_v1"(
      label: "Meldungen",
      labelIcon: "bell",
      labelColor: "STANDARD",
      contents: {
        if(
          a!isNullOrEmpty(local!notifications.data), 
          #"SYSTEM_SYSRULES_richTextDisplayField"(
            value: #"SYSTEM_SYSRULES_richTextItem_v1"(
              text: "Aktuell gibt es keine Meldungen",
              style: "EMPHASIS"                            
            ),
            align: "CENTER",
            marginAbove: "MORE"
          ),
          /* Meldungsliste */
          #"SYSTEM_SYSRULES_forEach"(
            items: {
              local!notifications.data
            },
            expression: #"SYSTEM_SYSRULES_cardLayout"(
              contents: {
                #"SYSTEM_SYSRULES_sideBySideLayout"(
                  items: {
                    #"SYSTEM_SYSRULES_sideBySideItem"(
                      item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                        labelPosition: "COLLAPSED",
                        value: {
                          #"SYSTEM_SYSRULES_richTextItem_v1"(
                            text: fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/8a98c023-d198-487c-826d-1b1a5fe05556"],
                            size: "MEDIUM_PLUS",
                          ),
                          char(10),
                          #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1609689"(dateTime: fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/53b2c144-14a6-4aba-8c99-9959510e556b"]),
                        }
                      )
                    ),
                    #"SYSTEM_SYSRULES_sideBySideItem"(
                      item: #"SYSTEM_SYSRULES_richTextDisplayField"(
                        labelPosition: "COLLAPSED",
                        value: #"SYSTEM_SYSRULES_richTextIcon"(
                          icon: "trash-o",
                          link: #"SYSTEM_SYSRULES_dynamicLink"(
                            saveInto: {
                              #"SYSTEM_SYSRULES_writeRecords_v2"(
                                records: #"urn:appian:record-type:v1:71bbaaf2-f886-43c9-8a84-0b885e738000"(
                                  #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/95e572b3-eaaa-4717-a233-55c853dce754": fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/95e572b3-eaaa-4717-a233-55c853dce754"],
                                  #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/cfe37f55-bc30-4340-b2a5-3cb36ff4e06b": false,
                                  #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/422ae8c3-03ea-4543-8738-9948dda16cff": now(),
                                  #"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/66ae7e9b-f76b-41af-9e54-799ea2305de2": loggedInUser()
                                ),
                              )
                            }
                          ),
                          color: "SECONDARY"
                        )
                      ),
                      width: "MINIMIZE"
                    )
                  },
                  alignVertical: "MIDDLE"
                ),
              },
              link: #"SYSTEM_SYSRULES_recordLink"(
                label: #"_a-0000ed87-2144-8000-9bee-011c48011c48_1418207"(requestType: fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/1884cbdb-9f47-4633-bc59-25181a783c76/8f6e62d6-f646-45a8-a038-e356580cbf87"]).translation 
                & " - " &
                #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1543632"(month: fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/1884cbdb-9f47-4633-bc59-25181a783c76/c705d2d0-bbc1-404a-bbc5-93cffc1a8c52"]) & " " & fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/1884cbdb-9f47-4633-bc59-25181a783c76/13ac8f18-8fd8-4341-8f42-86db1aaa8588"],
                recordType: #"urn:appian:record-type:v1:869b0f23-8e42-4780-8dfc-89deb24c798d",
                identifier: fv!item[#"urn:appian:record-field:v1:71bbaaf2-f886-43c9-8a84-0b885e738000/31895ddf-5be5-4ab0-9fca-08f37405a14c"],
                dashboard: "summary",
                openLinkIn: "NEW_TAB"
              ),
              style: "INFO",
              shape: "ROUNDED",
              marginBelow: "STANDARD",
              showBorder: false
            )
          )
        ),
        #"_a-0000ee0e-a4b3-8000-9bf2-011c48011c48_1616691"(
          pagingInfo: local!notificationsPagingInfo,
          saveInto: local!notificationsPagingInfo,
          totalCount: local!notifications.totalCount,
          align: "CENTER"
        )
      }
    )
  )
)
